#include<bits/stdc++.h>
using namespace std;
int a[100010],b[100010],len[100010],ans=INT_MAX;
map<int,int> mp;
int main()
{
    int n,k=0;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        int flag=0,min1=INT_MAX,min2;
        if(!mp[a[i]-1])
        {
            k++;
            len[k]=1;
            mp[a[i]]++;
            b[k]=a[i];
            continue;
        }
        for(int j=1;j<=k;j++)
        {
            if(a[i]==b[j]+1&&len[j]<min1)
            {
                flag=1;
                min1=len[j];
                min2=j;
            }
        }
        if(flag==0)
        {
            k++;
            len[k]=1;
            mp[a[i]]++;
            b[k]=a[i];
        }
        else
        {
            len[min2]++;
            b[min2]=a[i];
            mp[a[i]-1]--;
            mp[a[i]]++;
        }
    }
    for(int i=1;i<=k;i++)
    {
        ans=min(ans,len[i]);
    }
    printf("%d",ans);
    return 0;
}
